// // This module decrements a 4-bit counter on each clock cycle and resets to 15 when the reset input is high. The module has an additional input, disable, which will prevent the counter from decrementing when it is low.
module counter_4bit (
  input clk,
  input reset,
  input enable,
  output reg [3:0] count
);

  always @(posedge clk) begin
    if (reset) begin
      count <= 4'b0;
    end else if (enable) begin
      count <= count + 1;
    end
  end

endmodule
